er}.modal-icon{width:58px;height:58px;margin:0 auto 16px;display:grid;place-items:center;border-radius:50%;color:#fff;font-size:28px;font-weight:900}.modal-icon.success{background:var(--green)}.modal-icon.error{background:var(--red)}.modal-card h2{margin:0;font-size:24px}.modal-card p{margin:12px 0 0;color:var(--muted);font-size:16px;line-height:1.5}.modal-hint{margin-top:18px;color:#9aa4b3;font-size:12px}.overlay{display:none}@media(max-width:800px){.app{display:block}.sidebar{position:fixed;left:0;top:0;width:292px;transform:translateX(-105%);transition:.22s;box-shadow:20px 0 50px rgba(0,0,0,.28)}body.menu-open .sidebar{transform:translateX(0)}.overlay{display:block;position:fixed;inset:0;background:rgba(2,10,23,.52);opacity:0;pointer-events:none;transition:.22s;z-index:20}body.menu-open .overlay{opacity:1;pointer-events:auto}.main{padding:20px 16px}.menu-btn{display:grid;place-items:center}.heading h1{font-size:29px}.source-head{grid-template-columns:1fr auto;padding-right:74px}.source-account{grid-column:1/-1}.source-statuses{grid-column:2;grid-row:1 / span 2;flex-direction:column}.form-grid{grid-template-columns:1fr}.toolbar .btn{width:100%}.source-check-btn{width:100%}.edit-actions .btn{font-size:12px;padding:8px 5px}}
