<script>
const addForm=document.getElementById('add-source-form');
document.getElementById('show-add-source')?.addEventListener('click',()=>addForm?.classList.add('open'));
document.getElementById('hide-add-source')?.addEventListener('click',()=>addForm?.classList.remove('open'));
document.querySelectorAll('[data-source-edit]').forEach(button=>button.addEventListener('click',()=>button.closest('[data-source-card]').classList.add('active')));
document.querySelectorAll('[data-source-back]').forEach(button=>button.addEventListener('click',()=>{const card=button.closest('[data-source-card]');card.classList.remove('active');card.scrollIntoView({behavior:'smooth',block:'start'});}));
document.getElementById('check-modal')?.addEventListener('click',event=>event.currentTarget.remove());
</script>
